values.content:
=Eres un copywriter experto en ads de alto rendimiento para  {{ $('Edit Fields').item.json.Plataforma }}.

BRIEF:
- Negocio: {{ $('Edit Fields').item.json.Negocio }}
- Producto/Servicio: {{ $('Edit Fields').item.json.Producto_Servicio }}
- Objetivo: {{ $('Edit Fields').item.json.Objetivo }}
- CTA: {{ $('Edit Fields').item.json['CTA Deseado'] }}
- Idioma: {{ $('Edit Fields').item.json.Idioma }}

TAREA:
Genera 6 variaciones de copy publicitario, cada una con:

1. **Gancho (Hook):** Primera línea que captura atención (40-60 caracteres)
2. **Cuerpo (Body):** Mensaje principal con beneficios (100-150 palabras)
3. **CTA:** Llamado a la acción claro

FORMATOS A CREAR:
- 2 copys orientados a dolor/problema
- 2 copys orientados a beneficio/resultado
- 2 copys con prueba social/urgencia

RESTRICCIONES:
- Lenguaje {{ $('Edit Fields').item.json.Idioma }}
- Tono conversacional y persuasivo
- Enfocado en {{ $('Edit Fields').item.json.Objetivo }}
- Sin emojis excesivos (máximo 2 por copy)

RESPONDE EN JSON:
{
  "copys": [
    {
      "id": 1,
      "enfoque": "dolor|beneficio|prueba_social",
      "gancho": "...",
      "cuerpo": "...",
      "cta": "...",
      "notas": "Por qué este copy funciona"
    }
  ]
}

parameters.jsCode:
// Get all items from merge
const items = $input.all();

// Access brief data from first item json property
const brief = items[0].json;

// Parse estructura from output field of first item, handling both string and object types
let estructura;
if (typeof items[0].json.output === 'string') {
  try {
    estructura = JSON.parse(items[0].json.output);
  } catch (e) {
    estructura = { calendario: { duracion_dias: 30 }, adsets: [] };
  }
} else {
  estructura = items[0].json.output || { calendario: { duracion_dias: 30 }, adsets: [] };
}

// Convert Presupuesto dropdown text to numeric value
let presupuestoTotal;
if (brief.Presupuesto === 'Menos de 1000') {
  presupuestoTotal = 800;
} else if (brief.Presupuesto === '1000 a 3000') {
  presupuestoTotal = 2000;
} else if (brief.Presupuesto === 'Mas de 5000') {
  presupuestoTotal = 5000;
} else {
  presupuestoTotal = 2000; // default
}

const duracionDias = estructura.calendario?.duracion_dias || 30;
const numAdsets = estructura.adsets?.length || 3;

// Calculate presupuestoDiario by dividing presupuestoTotal by duracionDias
const presupuestoDiario = presupuestoTotal / duracionDias;

// Calculate presupuestoPorAdset by dividing presupuestoDiario by numAdsets
const presupuestoPorAdset = presupuestoDiario / numAdsets;

// Map distribucion_adsets with nombre, presupuesto_diario, presupuesto_total, and porcentaje for each adset
const distribucion_adsets = (estructura.adsets || []).map((adset, index) => ({
  nombre: adset.nombre,
  presupuesto_diario: Math.round(presupuestoPorAdset * 100) / 100,
  presupuesto_total: Math.round(presupuestoPorAdset * duracionDias * 100) / 100,
  porcentaje: Math.round((100 / numAdsets) * 100) / 100
}));

// Set cpm_estimado to 8 if Plataforma includes 'meta', otherwise 12
const cpm_estimado = (brief.Plataforma || '').toLowerCase().includes('meta') ? 8 : 12;

// Set ctr_objetivo to 2 if Objetivo includes 'ventas', otherwise 3
const ctr_objetivo = (brief.Objetivo || '').toLowerCase().includes('ventas') ? 2 : 3;

// Create recomendaciones
const recomendaciones = {
  presupuesto_total: presupuestoTotal,
  duracion_dias: duracionDias,
  presupuesto_diario_total: Math.round(presupuestoDiario * 100) / 100,
  presupuesto_por_adset: Math.round(presupuestoPorAdset * 100) / 100,
  distribucion_adsets: distribucion_adsets,
  metricas_esperadas: {
    cpm_estimado: cpm_estimado,
    ctr_objetivo: ctr_objetivo,
    impresiones_estimadas: Math.round((presupuestoTotal / cpm_estimado) * 1000)
  },
  recomendaciones: [
    "Comenzar con 50% del presupuesto en los primeros 7 días para testear",
    "Pausar adsets con CPM >$15 después de 3 días",
    "Escalar los ganadores en un 20% cada 3 días",
    "Mantener mínimo $10/día por adset para datos significativos"
  ]
};

// Return json object with spread brief, estructura, and presupuesto recomendaciones
return {
  json: {
    ...brief,
    estructura,
    presupuesto: recomendaciones
  }
};

// Get all items from merge
const items = $input.all();

// Access brief data from first item (Edit Fields output)
const brief = items[0].json;

// Get copys data from second item
let copys = [];
try {
  const copysOutput = items[1]?.json?.output;
  if (copysOutput && copysOutput[0]?.content?.[0]?.text) {
    const parsedData = JSON.parse(copysOutput[0].content[0].text);
    copys = parsedData.copys || [];
  }
} catch (e) {
  // Fallback to empty array if parsing fails
  copys = [];
}

// Generate current date
const currentDate = new Date().toISOString().split('T')[0];

const html = `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Copys - ${brief.Negocio}</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 800px; margin: 40px auto; padding: 20px; }
        h1 { color: #1a73e8; border-bottom: 3px solid #1a73e8; padding-bottom: 10px; }
        h2 { color: #5f6368; margin-top: 30px; }
        .copy-card { background: #f8f9fa; padding: 20px; margin: 20px 0; border-left: 4px solid #1a73e8; border-radius: 5px; }
        .gancho { font-weight: bold; font-size: 1.2em; color: #1a73e8; margin-bottom: 10px; }
        .cuerpo { line-height: 1.6; margin: 15px 0; }
        .cta { background: #1a73e8; color: white; padding: 10px 20px; display: inline-block; border-radius: 5px; margin-top: 10px; }
        .meta { color: #5f6368; font-size: 0.9em; font-style: italic; margin-top: 10px; }
    </style>
</head>
<body>
    <h1>📝 Copys Publicitarios - ${brief.Negocio}</h1>
    <p><strong>Producto:</strong> ${brief.Producto_Servicio}</p>
    <p><strong>Objetivo:</strong> ${brief.Objetivo}</p>
    <p><strong>Fecha:</strong> ${currentDate}</p>

    <h2>✨ Variaciones de Copy</h2>

    ${copys.length > 0 ? copys.map((copy, index) => `
        <div class="copy-card">
            <h3>Copy #${copy.id} - ${copy.enfoque.toUpperCase()}</h3>
            <div class="gancho">🎯 ${copy.gancho}</div>
            <div class="cuerpo">${copy.cuerpo}</div>
            <div class="cta">👉 ${copy.cta}</div>
            <div class="meta">💡 ${copy.notas}</div>
        </div>
    `).join('') : '<p>No se generaron copys.</p>'}

    <h2>📊 Recomendaciones de Uso</h2>
    <ul>
        <li>Testear los copys orientados a "dolor" primero para audiencias frías</li>
        <li>Usar copys de "beneficio" para retargeting</li>
        <li>Rotar copys cada 3-5 días para evitar fatiga de audiencia</li>
        <li>Combinar con diferentes creativos para maximizar variaciones</li>
    </ul>
</body>
</html>
`;

return {
    json: {
        htmlContent: html,
        fileName: `Copys_${brief.Negocio}_${currentDate}.html`
    }
};

